#!/usr/bin/env node
/*
 * vm.js - A MIPS32r2 (little-endian, o32) interpreter that runs the static ELF
 * `doomgeneric_mips`, implementing the Linux-style syscalls the binary makes
 * (the custom libc in my_stdlib.c issues real `syscall` instructions with
 * x86_64-style syscall numbers passed in $v0 and args in $a0-$a3/$t0/$t1).
 *
 * The program (doomgeneric_img.c) renders DOOM and writes each frame to
 * /tmp/frame.bmp via fopen/fwrite/fclose -> open/write/close syscalls.
 *
 * Usage:  node vm.js [path-to-elf]
 */
'use strict';

const fs = require('fs');
const path = require('path');

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
const ELF_PATH = process.argv[2] ||
  (fs.existsSync(path.join(__dirname, 'doomgeneric_mips'))
    ? path.join(__dirname, 'doomgeneric_mips')
    : './doomgeneric_mips');

// Flat guest memory.  Guest virtual addresses are used directly as indices.
//   .text/.rodata @ 0x00400000 ...
//   .data/.bss    @ 0x00466520 .. _end = 0x404b1790 (includes a 1GB static heap)
// Stack is placed above _end.
const MEM_SIZE  = 0x41100000;          // ~1.09 GiB, covers everything + stack
const STACK_TOP = 0x41000000;          // initial $sp region top
const GP_VALUE  = 0x0047d090;          // _gp (from .reginfo / symbol table)

const FRAMES_TO_SAVE = parseInt(process.env.VM_FRAMES || '3', 10); // then exit(0)

if (new Uint8Array(new Uint32Array([1]).buffer)[0] !== 1) {
  console.error('vm.js requires a little-endian host'); process.exit(1);
}

// ---------------------------------------------------------------------------
// Memory
// ---------------------------------------------------------------------------
const membuf = new ArrayBuffer(MEM_SIZE);
const u8   = new Uint8Array(membuf);
const i8   = new Int8Array(membuf);
const u16  = new Uint16Array(membuf);
const i16  = new Int16Array(membuf);
const u32  = new Uint32Array(membuf);
const i32  = new Int32Array(membuf);
const mem32 = i32;                       // alias for aligned 32-bit access
const dv   = new DataView(membuf);

function rd32(a){ return (a & 3) === 0 ? mem32[a >>> 2] : dv.getInt32(a, true); }
function wr32(a, v){ if ((a & 3) === 0) mem32[a >>> 2] = v; else dv.setInt32(a, v, true); }
function rd16s(a){ return (a & 1) === 0 ? i16[a >>> 1] : dv.getInt16(a, true); }
function rd16u(a){ return (a & 1) === 0 ? u16[a >>> 1] : dv.getUint16(a, true); }
function wr16(a, v){ if ((a & 1) === 0) u16[a >>> 1] = v & 0xffff; else dv.setUint16(a, v & 0xffff, true); }

function readCString(addr){
  let s = '';
  addr >>>= 0;
  for (;;) {
    const c = u8[addr++];
    if (c === 0 || c === undefined) break;
    s += String.fromCharCode(c);
  }
  return s;
}

// ---------------------------------------------------------------------------
// ELF loader (ELF32, little-endian)
// ---------------------------------------------------------------------------
function loadElf(file){
  const e = fs.readFileSync(file);
  if (!(e[0] === 0x7f && e[1] === 0x45 && e[2] === 0x4c && e[3] === 0x46))
    throw new Error('not an ELF file');
  const entry  = e.readUInt32LE(24);
  const phoff  = e.readUInt32LE(28);
  const phentsize = e.readUInt16LE(42);
  const phnum  = e.readUInt16LE(44);
  for (let i = 0; i < phnum; i++) {
    const off = phoff + i * phentsize;
    const p_type   = e.readUInt32LE(off);
    const p_offset = e.readUInt32LE(off + 4);
    const p_vaddr  = e.readUInt32LE(off + 8);
    const p_filesz = e.readUInt32LE(off + 16);
    if (p_type === 1 /* PT_LOAD */ && p_filesz > 0) {
      u8.set(e.subarray(p_offset, p_offset + p_filesz), p_vaddr);
    }
  }
  return entry >>> 0;
}

// ---------------------------------------------------------------------------
// CPU state
// ---------------------------------------------------------------------------
const r = new Int32Array(32);   // general purpose registers (r[0] hardwired 0)
let hi = 0, lo = 0;             // HI/LO

// FPU: 32 x 32-bit registers; doubles use even/odd pairs (o32 / FR=0)
const fbuf = new ArrayBuffer(32 * 4);
const f32  = new Float32Array(fbuf);   // single at register index
const f64  = new Float64Array(fbuf);   // double at (reg>>1)
const fi32 = new Int32Array(fbuf);     // raw bits (signed)
let   fcc  = 0;                        // FP condition codes (bit n = cc n)

function rotr(v, s){ s &= 31; return s === 0 ? v : ((v >>> s) | (v << (32 - s))) | 0; }

// signed 64-bit multiply -> hi/lo
function mult(a, b){
  const au = a >>> 0, bu = b >>> 0;
  const aL = au & 0xffff, aH = au >>> 16, bL = bu & 0xffff, bH = bu >>> 16;
  const ll = aL * bL, lh = aL * bH, hl = aH * bL, hh = aH * bH;
  const cross = (ll >>> 16) + (lh & 0xffff) + (hl & 0xffff);
  lo = (((ll & 0xffff) | ((cross & 0xffff) << 16)) >>> 0) | 0;
  let hiU = (hh + (lh >>> 16) + (hl >>> 16) + (cross >>> 16)) >>> 0;
  if (a < 0) hiU = (hiU - bu) >>> 0;
  if (b < 0) hiU = (hiU - au) >>> 0;
  hi = hiU | 0;
}
function multu(a, b){
  const au = a >>> 0, bu = b >>> 0;
  const aL = au & 0xffff, aH = au >>> 16, bL = bu & 0xffff, bH = bu >>> 16;
  const ll = aL * bL, lh = aL * bH, hl = aH * bL, hh = aH * bH;
  const cross = (ll >>> 16) + (lh & 0xffff) + (hl & 0xffff);
  lo = (((ll & 0xffff) | ((cross & 0xffff) << 16)) >>> 0) | 0;
  hi = ((hh + (lh >>> 16) + (hl >>> 16) + (cross >>> 16)) >>> 0) | 0;
}

// ---------------------------------------------------------------------------
// Syscalls (numbers match the x86_64-style set used by my_stdlib.c)
// ---------------------------------------------------------------------------
const SYS = {
  read: 0, write: 1, open: 2, close: 3, lseek: 8,
  nanosleep: 35, exit: 60, fsync: 74, rename: 82, mkdir: 83,
  unlink: 87, gettimeofday: 96, time: 201,
};
const O_RDONLY = 0, O_WRONLY = 1, O_RDWR = 2, O_CREAT = 64, O_TRUNC = 512, O_APPEND = 1024;

const files = new Map();   // guestFd -> { hostFd, pos }
let nextFd = 3;
let framesWritten = 0;

function resolvePath(p){
  if (p.startsWith('/')) return p;
  if (fs.existsSync(p)) return p;
  const alt = path.join(__dirname, p);
  if (fs.existsSync(alt)) return alt;
  return p;
}

function nodeFlags(flags){
  const acc = flags & 3;
  const creat = (flags & O_CREAT) !== 0;
  const trunc = (flags & O_TRUNC) !== 0;
  const append = (flags & O_APPEND) !== 0;
  if (acc === O_RDONLY) return 'r';
  if (acc === O_WRONLY) {
    if (append) return 'a';
    if (trunc || creat) return 'w';
    return 'r+';
  }
  // O_RDWR
  if (append) return 'a+';
  if (trunc) return 'w+';
  if (creat) return 'w+';
  return 'r+';
}

function doSyscall(){
  const num = r[2] | 0;          // $v0
  const a0 = r[4] | 0, a1 = r[5] | 0, a2 = r[6] | 0, a3 = r[7] | 0;
  let ret = 0;
  try {
    switch (num) {
      case SYS.write: {
        const fd = a0, buf = a0, count = a2 >>> 0;
        void buf;
        if (a0 === 1 || a0 === 2) {
          const chunk = Buffer.from(u8.slice(a1 >>> 0, (a1 >>> 0) + count));
          if (a0 === 1) process.stdout.write(chunk); else process.stderr.write(chunk);
          ret = count;
        } else {
          const f = files.get(fd);
          if (!f) { ret = -9; break; }
          const b = Buffer.from(membuf, a1 >>> 0, count);
          const n = fs.writeSync(f.hostFd, b, 0, count, f.pos);
          f.pos += n;
          ret = n;
          if (f.isFrame && f.pos >= 0) f.wroteData = true;
        }
        break;
      }
      case SYS.read: {
        const f = files.get(a0);
        if (!f) { ret = -9; break; }
        const count = a2 >>> 0;
        const b = Buffer.from(membuf, a1 >>> 0, count);
        const n = fs.readSync(f.hostFd, b, 0, count, f.pos);
        f.pos += n;
        ret = n;
        break;
      }
      case SYS.open: {
        const p = readCString(a0);
        const flags = a1 | 0;
        const rp = resolvePath(p);
        const isFrame = (rp === '/tmp/frame.bmp' || p === '/tmp/frame.bmp');
        let hostFd;
        try {
          hostFd = fs.openSync(rp, nodeFlags(flags), (a2 & 0o777) || 0o644);
        } catch (err) {
          ret = -2; // -ENOENT
          break;
        }
        const gfd = nextFd++;
        files.set(gfd, { hostFd, pos: 0, isFrame, wroteData: false });
        ret = gfd;
        break;
      }
      case SYS.close: {
        const f = files.get(a0);
        if (!f) { ret = -9; break; }
        try { fs.closeSync(f.hostFd); } catch (e) {}
        files.delete(a0);
        if (f.isFrame) {
          framesWritten++;
          console.error(`[vm] frame #${framesWritten} written to /tmp/frame.bmp`);
          if (framesWritten >= FRAMES_TO_SAVE) {
            r[2] = 0;
            shutdown(0);
          }
        }
        ret = 0;
        break;
      }
      case SYS.lseek: {
        const f = files.get(a0);
        if (!f) { ret = -9; break; }
        const off = a1 | 0, whence = a2 | 0;
        if (whence === 0) f.pos = off;              // SEEK_SET
        else if (whence === 1) f.pos += off;         // SEEK_CUR
        else if (whence === 2) {                     // SEEK_END
          const sz = fs.fstatSync(f.hostFd).size;
          f.pos = sz + off;
        }
        ret = f.pos;
        break;
      }
      case SYS.fsync: ret = 0; break;
      case SYS.nanosleep: ret = 0; break;
      case SYS.rename: {
        try { fs.renameSync(resolvePath(readCString(a0)), resolvePath(readCString(a1))); ret = 0; }
        catch (e) { ret = -2; }
        break;
      }
      case SYS.mkdir: {
        try { fs.mkdirSync(resolvePath(readCString(a0))); ret = 0; }
        catch (e) { ret = (e && e.code === 'EEXIST') ? -17 : -2; }
        break;
      }
      case SYS.unlink: {
        try { fs.unlinkSync(resolvePath(readCString(a0))); ret = 0; }
        catch (e) { ret = -2; }
        break;
      }
      case SYS.time: {
        const t = Math.floor(Date.now() / 1000) | 0;
        if (a0 !== 0) wr32(a0 >>> 0, t);
        ret = t;
        break;
      }
      case SYS.gettimeofday: {
        if (a0 !== 0) {
          const ms = Date.now();
          wr32(a0 >>> 0, (Math.floor(ms / 1000)) | 0);
          wr32((a0 + 4) >>> 0, ((ms % 1000) * 1000) | 0);
        }
        ret = 0;
        break;
      }
      case SYS.exit:
        shutdown(a0 | 0);
        ret = 0;
        break;
      default:
        console.error(`[vm] unhandled syscall ${num} (a0=${a0} a1=${a1} a2=${a2})`);
        ret = -38; // -ENOSYS
    }
  } catch (err) {
    console.error('[vm] syscall error', num, err && err.message);
    ret = -1;
  }
  r[2] = ret | 0;   // return value in $v0
}

function shutdown(code){
  for (const f of files.values()) { try { fs.closeSync(f.hostFd); } catch (e) {} }
  process.exit(code);
}

// ---------------------------------------------------------------------------
// COP1 (FPU) handler
// ---------------------------------------------------------------------------
function cop1(inst, pc){
  const fmt = (inst >>> 21) & 0x1f;
  const ft  = (inst >>> 16) & 0x1f;
  const fs  = (inst >>> 11) & 0x1f;
  const fd  = (inst >>> 6)  & 0x1f;
  const funct = inst & 0x3f;
  let branchTarget = -1;
  switch (fmt) {
    case 0x00: // MFC1
      if (ft) r[ft] = fi32[fs];
      break;
    case 0x03: // MFHC1
      if (ft) r[ft] = fi32[fs + 1];
      break;
    case 0x04: // MTC1
      fi32[fs] = r[ft];
      break;
    case 0x07: // MTHC1
      fi32[fs + 1] = r[ft];
      break;
    case 0x02: // CFC1 (stub)
      if (ft) r[ft] = (fs === 31) ? ((fcc & 1) << 23) : 0;
      break;
    case 0x06: // CTC1 (stub)
      break;
    case 0x08: { // BC1
      const tf = (inst >>> 16) & 1;
      const cc = (inst >>> 18) & 7;
      const cond = ((fcc >>> cc) & 1) === tf;
      if (cond) {
        const off = (inst << 16) >> 16;
        branchTarget = (pc + 4 + (off << 2)) >>> 0;
      }
      break;
    }
    case 0x10: // single
      cop1fmt(inst, funct, fd, fs, ft, false);
      break;
    case 0x11: // double
      cop1fmt(inst, funct, fd, fs, ft, true);
      break;
    case 0x14: // word -> convert
      if (funct === 0x20) f32[fd] = fi32[fs];            // cvt.s.w
      else if (funct === 0x21) f64[fd >> 1] = fi32[fs];  // cvt.d.w
      break;
    case 0x15: // long (unused)
      if (funct === 0x20) f32[fd] = fi32[fs];
      else if (funct === 0x21) f64[fd >> 1] = fi32[fs];
      break;
    default:
      console.error(`[vm] unhandled COP1 fmt 0x${fmt.toString(16)} @0x${pc.toString(16)}`);
  }
  return branchTarget;
}

function toInt32Trunc(v){
  if (!isFinite(v)) return 0x7fffffff;
  const t = Math.trunc(v);
  if (t >= 2147483647) return 0x7fffffff;
  if (t <= -2147483648) return -2147483648;
  return t | 0;
}

function cop1fmt(inst, funct, fd, fs, ft, dbl){
  if (funct >= 0x30) { // c.cond.fmt
    const cc = (inst >>> 8) & 7;
    const a = dbl ? f64[fs >> 1] : f32[fs];
    const b = dbl ? f64[ft >> 1] : f32[ft];
    let cond;
    switch (funct) {
      case 0x30: cond = false; break;                       // c.f
      case 0x32: cond = (a === b); break;                    // c.eq
      case 0x34: cond = (a < b); break;                      // c.olt / c.lt
      case 0x36: cond = (a <= b); break;                     // c.ole / c.le
      case 0x3c: cond = (a < b); break;                      // c.lt (unordered variant)
      case 0x3e: cond = (a <= b); break;                     // c.le
      case 0x31: case 0x33: case 0x35: case 0x37:            // unordered variants
        cond = (isNaN(a) || isNaN(b)) ? true :
               (funct === 0x33 ? a === b : funct === 0x35 ? a < b : funct === 0x37 ? a <= b : false);
        break;
      default: cond = (a < b);
    }
    if (cond) fcc |= (1 << cc); else fcc &= ~(1 << cc);
    return;
  }
  switch (funct) {
    case 0x00: if (dbl) f64[fd >> 1] = f64[fs >> 1] + f64[ft >> 1]; else f32[fd] = f32[fs] + f32[ft]; break; // add
    case 0x01: if (dbl) f64[fd >> 1] = f64[fs >> 1] - f64[ft >> 1]; else f32[fd] = f32[fs] - f32[ft]; break; // sub
    case 0x02: if (dbl) f64[fd >> 1] = f64[fs >> 1] * f64[ft >> 1]; else f32[fd] = f32[fs] * f32[ft]; break; // mul
    case 0x03: if (dbl) f64[fd >> 1] = f64[fs >> 1] / f64[ft >> 1]; else f32[fd] = f32[fs] / f32[ft]; break; // div
    case 0x04: if (dbl) f64[fd >> 1] = Math.sqrt(f64[fs >> 1]); else f32[fd] = Math.sqrt(f32[fs]); break;      // sqrt
    case 0x05: if (dbl) f64[fd >> 1] = Math.abs(f64[fs >> 1]); else f32[fd] = Math.abs(f32[fs]); break;        // abs
    case 0x06: // mov (bit copy)
      if (dbl) { fi32[fd] = fi32[fs]; fi32[fd + 1] = fi32[fs + 1]; }
      else fi32[fd] = fi32[fs];
      break;
    case 0x07: if (dbl) f64[fd >> 1] = -f64[fs >> 1]; else f32[fd] = -f32[fs]; break; // neg
    case 0x0d: // trunc.w
      fi32[fd] = toInt32Trunc(dbl ? f64[fs >> 1] : f32[fs]);
      break;
    case 0x0c: // round.w
      fi32[fd] = toInt32Trunc(Math.round(dbl ? f64[fs >> 1] : f32[fs]));
      break;
    case 0x0e: // ceil.w
      fi32[fd] = toInt32Trunc(Math.ceil(dbl ? f64[fs >> 1] : f32[fs]));
      break;
    case 0x0f: // floor.w
      fi32[fd] = toInt32Trunc(Math.floor(dbl ? f64[fs >> 1] : f32[fs]));
      break;
    case 0x11: { // movt/movf.fmt
      const tf = (inst >>> 16) & 1;
      const cc = (inst >>> 18) & 7;
      if (((fcc >>> cc) & 1) === tf) {
        if (dbl) { fi32[fd] = fi32[fs]; fi32[fd + 1] = fi32[fs + 1]; }
        else fi32[fd] = fi32[fs];
      }
      break;
    }
    case 0x20: // cvt.s
      f32[fd] = dbl ? f64[fs >> 1] : f32[fs];
      break;
    case 0x21: // cvt.d
      f64[fd >> 1] = dbl ? f64[fs >> 1] : f32[fs];
      break;
    case 0x24: // cvt.w (round-to-nearest as default)
      fi32[fd] = toInt32Trunc(Math.round(dbl ? f64[fs >> 1] : f32[fs]));
      break;
    default:
      console.error(`[vm] unhandled COP1 op funct 0x${funct.toString(16)} dbl=${dbl}`);
  }
}

// ---------------------------------------------------------------------------
// Main interpreter loop
// ---------------------------------------------------------------------------
function run(entry){
  let pc = entry >>> 0;
  let npc = (entry + 4) >>> 0;

  for (;;) {
    r[0] = 0;
    if (pc >= MEM_SIZE) throw new Error('PC out of range: 0x' + pc.toString(16));
    const inst = u32[pc >>> 2];
    let target = (npc + 4) >>> 0;   // default next-next PC (delay-slot semantics)

    const op = inst >>> 26;
    switch (op) {
      case 0x00: { // SPECIAL
        const funct = inst & 0x3f;
        const rs = (inst >>> 21) & 0x1f;
        const rt = (inst >>> 16) & 0x1f;
        const rd = (inst >>> 11) & 0x1f;
        const sa = (inst >>> 6) & 0x1f;
        switch (funct) {
          case 0x00: if (rd) r[rd] = r[rt] << sa; break;                    // sll
          case 0x02: if (rd) r[rd] = ((inst >>> 21) & 1) ? rotr(r[rt], sa) : (r[rt] >>> sa) | 0; break; // srl/rotr
          case 0x03: if (rd) r[rd] = r[rt] >> sa; break;                     // sra
          case 0x04: if (rd) r[rd] = r[rt] << (r[rs] & 31); break;           // sllv
          case 0x06: if (rd) r[rd] = ((inst >>> 6) & 1) ? rotr(r[rt], r[rs] & 31) : (r[rt] >>> (r[rs] & 31)) | 0; break; // srlv/rotrv
          case 0x07: if (rd) r[rd] = r[rt] >> (r[rs] & 31); break;           // srav
          case 0x08: target = r[rs] >>> 0; break;                            // jr
          case 0x09: if (rd) r[rd] = (pc + 8) | 0; target = r[rs] >>> 0; break; // jalr
          case 0x0a: if (r[rt] === 0) { if (rd) r[rd] = r[rs]; } break;      // movz
          case 0x0b: if (r[rt] !== 0) { if (rd) r[rd] = r[rs]; } break;      // movn
          case 0x0c: pc = npc = 0; doSyscall(); pc = pc; break;             // syscall (handled below)
          case 0x0d: throw new Error('BREAK @0x' + pc.toString(16));         // break
          case 0x0f: break;                                                  // sync
          case 0x10: if (rd) r[rd] = hi; break;                              // mfhi
          case 0x11: hi = r[rs]; break;                                      // mthi
          case 0x12: if (rd) r[rd] = lo; break;                              // mflo
          case 0x13: lo = r[rs]; break;                                      // mtlo
          case 0x18: mult(r[rs], r[rt]); break;                              // mult
          case 0x19: multu(r[rs], r[rt]); break;                             // multu
          case 0x1a: { const b = r[rt]; if (b === 0) { lo = 0; hi = 0; } else { lo = (r[rs] / b) | 0; hi = (r[rs] % b) | 0; } break; } // div
          case 0x1b: { const a = r[rs] >>> 0, b = r[rt] >>> 0; if (b === 0) { lo = 0; hi = 0; } else { lo = (Math.floor(a / b)) | 0; hi = (a % b) | 0; } break; } // divu
          case 0x20: if (rd) r[rd] = (r[rs] + r[rt]) | 0; break;             // add
          case 0x21: if (rd) r[rd] = (r[rs] + r[rt]) | 0; break;             // addu
          case 0x22: if (rd) r[rd] = (r[rs] - r[rt]) | 0; break;             // sub
          case 0x23: if (rd) r[rd] = (r[rs] - r[rt]) | 0; break;             // subu
          case 0x24: if (rd) r[rd] = r[rs] & r[rt]; break;                   // and
          case 0x25: if (rd) r[rd] = r[rs] | r[rt]; break;                   // or
          case 0x26: if (rd) r[rd] = r[rs] ^ r[rt]; break;                   // xor
          case 0x27: if (rd) r[rd] = ~(r[rs] | r[rt]); break;                // nor
          case 0x2a: if (rd) r[rd] = (r[rs] < r[rt]) ? 1 : 0; break;         // slt
          case 0x2b: if (rd) r[rd] = ((r[rs] >>> 0) < (r[rt] >>> 0)) ? 1 : 0; break; // sltu
          case 0x34: if (r[rs] === r[rt]) throw new Error('TEQ trap @0x' + pc.toString(16)); break; // teq
          case 0x30: case 0x31: case 0x32: case 0x33: break;                 // tge/tgeu/tlt/tltu (ignore unless...)
          case 0x36: break;                                                  // tne (ignore)
          default: throw new Error(`unhandled SPECIAL funct 0x${funct.toString(16)} @0x${pc.toString(16)}`);
        }
        if (funct === 0x0c) { // syscall: advance normally
          pc = npc = 0; // placeholder, fixed below
        }
        break;
      }
      case 0x01: { // REGIMM
        const rs = (inst >>> 21) & 0x1f;
        const rtf = (inst >>> 16) & 0x1f;
        const off = (inst << 16) >> 16;
        let taken = false, link = false;
        switch (rtf) {
          case 0x00: taken = r[rs] < 0; break;              // bltz
          case 0x01: taken = r[rs] >= 0; break;             // bgez
          case 0x10: taken = r[rs] < 0; link = true; break; // bltzal
          case 0x11: taken = r[rs] >= 0; link = true; break;// bgezal
          default: taken = false;
        }
        if (link) r[31] = (pc + 8) | 0;
        if (taken) target = (pc + 4 + (off << 2)) >>> 0;
        break;
      }
      case 0x02: target = (((pc + 4) & 0xf0000000) | ((inst & 0x03ffffff) << 2)) >>> 0; break; // j
      case 0x03: r[31] = (pc + 8) | 0; target = (((pc + 4) & 0xf0000000) | ((inst & 0x03ffffff) << 2)) >>> 0; break; // jal
      case 0x04: { const rs = (inst >>> 21) & 0x1f, rt = (inst >>> 16) & 0x1f; if (r[rs] === r[rt]) target = (pc + 4 + (((inst << 16) >> 16) << 2)) >>> 0; break; } // beq
      case 0x05: { const rs = (inst >>> 21) & 0x1f, rt = (inst >>> 16) & 0x1f; if (r[rs] !== r[rt]) target = (pc + 4 + (((inst << 16) >> 16) << 2)) >>> 0; break; } // bne
      case 0x06: { const rs = (inst >>> 21) & 0x1f; if (r[rs] <= 0) target = (pc + 4 + (((inst << 16) >> 16) << 2)) >>> 0; break; } // blez
      case 0x07: { const rs = (inst >>> 21) & 0x1f; if (r[rs] > 0) target = (pc + 4 + (((inst << 16) >> 16) << 2)) >>> 0; break; } // bgtz
      case 0x08: // addi (treat as addiu, no overflow trap)
      case 0x09: { const rs = (inst >>> 21) & 0x1f, rt = (inst >>> 16) & 0x1f; if (rt) r[rt] = (r[rs] + ((inst << 16) >> 16)) | 0; break; } // addiu
      case 0x0a: { const rs = (inst >>> 21) & 0x1f, rt = (inst >>> 16) & 0x1f; if (rt) r[rt] = (r[rs] < ((inst << 16) >> 16)) ? 1 : 0; break; } // slti
      case 0x0b: { const rs = (inst >>> 21) & 0x1f, rt = (inst >>> 16) & 0x1f; if (rt) r[rt] = ((r[rs] >>> 0) < (((inst << 16) >> 16) >>> 0)) ? 1 : 0; break; } // sltiu
      case 0x0c: { const rs = (inst >>> 21) & 0x1f, rt = (inst >>> 16) & 0x1f; if (rt) r[rt] = r[rs] & (inst & 0xffff); break; } // andi
      case 0x0d: { const rs = (inst >>> 21) & 0x1f, rt = (inst >>> 16) & 0x1f; if (rt) r[rt] = r[rs] | (inst & 0xffff); break; } // ori
