}

// ---------------------------------------------------------------------------
// Boot
// ---------------------------------------------------------------------------
function main(){
  const entry = loadElf(ELF_PATH);
  r[28] = GP_VALUE | 0;              // $gp
  r[29] = (STACK_TOP - 16) | 0;      // $sp
  r[31] = 0;                         // $ra
  console.error(`[vm] booting ${ELF_PATH}  entry=0x${entry.toString(16)}  sp=0x${(r[29]>>>0).toString(16)}  gp=0x${(r[28]>>>0).toString(16)}`);
  try {
    run(entry);
  } catch (err) {
    console.error('[vm] halted:', err && err.message);
    shutdown(1);
  }
}

main();

